// Golden regression fixture - deterministic, speak-free
interface Greeting {
  recipient: string;
  enthusiasm: number;
}

const buildGreeting = (g: Greeting): string => {
  const punctuation = '!'.repeat(g.enthusiasm);
  return `Hello, ${g.recipient}${punctuation}`;
};

const greeting = buildGreeting({ recipient: 'CodeVideo', enthusiasm: 3 });
console.log(greeting);
